文件分析器 - 演示文件类型和内容分析功能
"""

from claude_agent_sdk import tool
from typing import Dict, Any
import os
import json
from pathlib import Path

@tool(
    name="analyze_file",
    description="分析文件的类型、大小、行数等基本信息",
    input_schema={
        "type": "object",
        "properties": {
            "file_path": {
                "type": "string",
                "description": "要分析的文件路径"
            },
            "analyze_content": {
                "type": "boolean",
                "description": "是否分析文件内容（如代码行数、注释等）",
                "default": False
            }
        },
        "required": ["file_path"]
    }
)
